@dataclass(frozen=True)
class OrderCreated(Event):
    order_id: UUID
    customer_id: UUID

@dataclass(frozen=True)
class OrderItemAdded(Event):
    order_id: UUID
    product_id: UUID
    product_name: str
    quantity: int
    unit_price: Decimal

@dataclass(frozen=True)
class OrderItemRemoved(Event):
    order_id: UUID
    product_id: UUID

@dataclass(frozen=True)
class OrderPlaced(Event):
    order_id: UUID
    shipping_address: dict
    total_amount: Decimal

@dataclass(frozen=True)
class OrderShipped(Event):
    order_id: UUID
    tracking_number: str
    carrier: str

@dataclass(frozen=True)
class OrderCancelled(Event):
    order_id: UUID
    reason: str
    cancelled_by: UUID
